<div class="theme-clean-meow nova-container">
  <div class="card-clean-meow">
    <div class="clean-header">
      <div>
        喵喵选择器
        <span>请选择你的答案吧~</span>
      </div>
    </div>

    <div class="button-group-clean">
      <button class="action-btn-clean" data-action="$1">$1</button>
      <button class="action-btn-clean" data-action="$2">$2</button>
      <button class="action-btn-clean" data-action="$3">$3</button>
      <button class="action-btn-clean" data-action="$4">$4</button>
    </div>

    <div class="font-controls">
      <button class="font-btn decrease-font">-</button>
      <span class="font-size-display">15</span>
      <button class="font-btn increase-font">+</button>
    </div>

    <div class="clean-footer">
      <div>
        <span class="cat-icon">🐾</span> 喵喵电波 <span class="cat-icon">🐾</span>
      </div>
    </div>
  </div>
</div>

<script>
// 创建星星背景
function createStars() {
  const container = document.querySelector('.theme-clean-meow');
  if (!container) return;

  for (let i = 0; i < 15; i++) {
    const star = document.createElement('div');
    star.className = 'star';
    star.style.width = `${Math.random() * 10 + 5}px`;
    star.style.height = star.style.width;
    star.style.left = `${Math.random() * 100}%`;
    star.style.top = `${Math.random() * 100}%`;
    star.style.opacity = Math.random() * 0.5 + 0.3;
    star.style.animationDelay = `${Math.random() * 3}s`;
    container.appendChild(star);
  }
}

// 选项点击处理
document.querySelectorAll('.action-btn-clean').forEach(btn => {
  btn.addEventListener('click', function() {
    // 移除所有active类
    document.querySelectorAll('.action-btn-clean').forEach(b => b.classList.remove('active'));
    // 为当前按钮添加active类
    this.classList.add('active');

    const originalText = this.getAttribute('data-action');

    try {
      // 优先使用triggerSlash方法
      if (window.parent && window.parent.triggerSlash) {
        window.parent.triggerSlash(`/setinput ${originalText}`);
      } else {
        // 备用方法：直接操作输入框
        const stInputElement = window.parent.document.querySelector('#send_textarea');
        if (stInputElement) {
          stInputElement.value = originalText;
          const event = new Event('input', { bubbles: true });
          stInputElement.dispatchEvent(event);
        }
      }
    } catch (error) {
      console.error('向输入框设置文本时出错:', error);
    }
  });
});

// 字体大小控制
let currentFontSize = 15;
const sizeDisplay = document.querySelector('.font-size-display');

function loadFontSize() {
  const savedSize = localStorage.getItem('card-button-font-size');
  if (savedSize) {
    currentFontSize = parseInt(savedSize);
    sizeDisplay.textContent = currentFontSize;
    document.documentElement.style.setProperty('--button-font-size', `${currentFontSize}px`);
  }
}

function saveFontSize(size) {
  localStorage.setItem('card-button-font-size', size);
}

document.querySelector('.decrease-font').addEventListener('click', () => {
  if (currentFontSize > 12) {
    currentFontSize--;
    sizeDisplay.textContent = currentFontSize;
    document.documentElement.style.setProperty('--button-font-size', `${currentFontSize}px`);
    saveFontSize(currentFontSize);
  }
});

document.querySelector('.increase-font').addEventListener('click', () => {
  if (currentFontSize < 20) {
    currentFontSize++;
    sizeDisplay.textContent = currentFontSize;
    document.documentElement.style.setProperty('--button-font-size', `${currentFontSize}px`);
    saveFontSize(currentFontSize);
  }
});

// 初始化
document.addEventListener('DOMContentLoaded', () => {
  createStars();
  loadFontSize();
});
</script>
</body>
</html>
